- 'Significant number of associated triggers' refers to more than 10 triggers;
- Bob Williams is the user setting up the alerts;
- Broadcom Inc. is the specific company associated with the alerts.

sql:
SELECT COUNT(DISTINCT c.company_id) AS num_companies_with_pe_ratio_above_average
FROM companies c
JOIN alerts a ON c.company_id = a.company_id AND a.metric_name = 'EPS' AND a.threshold < 40
JOIN financial_metrics f ON c.company_id = f.company_id AND f.pe_ratio > (
    SELECT AVG(pe_ratio) FROM financial_metrics
);

SELECT u.user_name, a.metric_name, a.threshold
FROM users u
INNER JOIN alerts a ON u.user_id = a.user_id;

